mapper.select:
		/* oms-master-serviceOrType-sql-oracle.xml selectOrTypeCount */
        SELECT COUNT(1)
          FROM TORDER_MST_ORTYPE A


			 	   #{SEARCH_CONDITION}

/* oms-master-serviceOrType-sql-oracle.xml selectOrTypeList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , A.OWKEY , O.OWNM AS OWKEYNM , A.ORDERTYPECD AS SERVERORDERTYPECD , A.ORDERTYPECD , A.ORDERTYPENM , COALESCE(A.IBYN, 'N') AS IBYN , COALESCE(A.OBYN, 'N') AS OBYN , A.ORDERAT , A.WMSIBTYPE , A.WMSOBTYPE , A.TMSOBTYPE , COALESCE(A.SOYN, 'N') AS SOYN , COALESCE(A.STOCKYN, 'N') AS STOCKYN , COALESCE(A.WMSORDERCREATEYN, 'N') AS WMSORDERCREATEYN , COALESCE(A.TMSORDERCREATEYN, 'N') AS TMSORDERCREATEYN , COALESCE(A.WMSYN, 'N') AS WMSYN , COALESCE(A.TMSPERFMANSYN, 'N') AS TMSPERFMANSYN , COALESCE(A.WMSPERFMANSYN, 'N') AS WMSPERFMANSYN , A.PERFMANSTYPE , COALESCE(A.ORDERSEPYN, 'N') AS ORDERSEPYN , COALESCE(A.ICCOMBINATYN, 'N') AS ICCOMBINATYN , 'Y' AS IS_OWSPCVERIFICATION , COALESCE(A.DELYN, 'N') AS DELYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY --, COALESCE(A.UNSETYN, 'N') AS UNSETYN --, COALESCE(A.ICUT_CHK_BY_CT_YN, 'N') AS ICUT_CHK_BY_CT_YN --, COALESCE(A.DLDAYYN, 'N') AS DLDAYYN --, A.OWSPCVERIFICATION FROM TORDER_MST_ORTYPE A LEFT JOIN TORDER_MST_OW O ON A.OWKEY = O.OWKEY WHERE 1 = 1
AND #{SEARCH_CONDITION}
AND A.OWKEY = #{owkey}
AND A.ORDERTYPECD = #{orTypeCd}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY LPAD(A.ORDERTYPECD::TEXT, 20, '0')
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

		SELECT COUNT(1)
		  FROM TORDER_MST_ORTYPE	
    	 WHERE OWKEY = #{owkey}
    	   AND ORDERTYPECD = #{ordertypecd}

		SELECT COUNT(1)
		  FROM TORDER_INFO_SO_CHK
    	 WHERE OWKEY = #{owkey}
    	   AND ORDERTYPECD = #{ordertypecd}	
    	   AND HDDTDIV = #{hddtdiv}
    	   AND SOCOLUMN = #{socolumn}

mapper.insert:
/* oms-master-serviceOrType-sql-oracle.xml insertOrTypeDt */
	INSERT INTO TORDER_INFO_SO_CHK
	(
	      OWKEY
	    , ORDERTYPECD
	    , HDDTDIV
	    , SOCOLUMN
	    , REQRDYN
	    , DEFVAL
	    , DELYN
	    , INSERTDATE
	    , INSERTURKEY
	    , UPDATEDATE
	    , UPDATEURKEY
	)
	VALUES 
	(
	      #{owkey}
	    , #{ordertypecd}
	    , #{hddtdiv}
	    , #{socolumn}
	    , #{reqrdyn}
	    , #{defval}
	    , #{delyn}
	    , #{sysdate}
	    , #{surkey}
	    , #{sysdate}
	    , #{surkey}
	)

mapper.update:
/* oms-master-serviceOrType-sql-oracle.xml updateOrTypeDt */
	UPDATE TORDER_INFO_SO_CHK
	   SET REQRDYN = #{reqrdyn}
	     , DEFVAL = #{defval}
	     , DELYN = #{delyn}
	     , UPDATEDATE = #{sysdate}
	     , UPDATEURKEY = #{surkey}
	 WHERE OWKEY = #{owkey}
	   AND ORDERTYPECD = #{ordertypecd}
	   AND HDDTDIV = #{hddtdiv}
	   AND SOCOLUMN = #{socolumn}
